import { useContext, useMemo, useEffect } from "react";
import Post from "./Post";
import styles from "./Posts.module.css";
import Header from "./Header";
import Footer from "./Footer";
import Nav from "./Nav";
import { BlogContext } from "./BlogContext";
import ReactGA from "react-ga";
import config from "./config";

const postsPerPage = 3;

function paginate(array, pageNumber) {
	return array.slice((pageNumber - 1) * postsPerPage, pageNumber * postsPerPage);
}

function getMaxPage(posts) {
	return posts.length % postsPerPage === 0 ? Math.floor(posts.length / postsPerPage) : Math.floor(posts.length / postsPerPage + 1);
}

function Posts(props) {
	const { page = 1 } = props.match.params;
	const posts = useContext(BlogContext);

	const currentPage = Math.floor(Math.min(Math.max(1, page), getMaxPage(posts)));

	const getGA = () => {
		const pathName = window.location.pathname;
		ReactGA.initialize(config.analytics);
		ReactGA.set({ page: pathName });
		ReactGA.pageview(pathName);
	};

	useEffect(() => {
		getGA();
	}, [currentPage]);
	useEffect(() => {
		window.scrollTo(0, 0);
	}, [page]);

	const filteredPosts = useMemo(() => paginate(posts, currentPage), [currentPage, posts]);

	const prevLink = useMemo(() => {
		return currentPage > 1 ? `/page/${currentPage - 1}` : null;
	}, [currentPage]);

	const nextLink = useMemo(() => {
		return currentPage < getMaxPage(posts) ? `/page/${currentPage + 1}` : null;
	}, [currentPage, posts]);

	return (
		<>
			<Header />
			<Nav prevLink={prevLink} nextLink={nextLink} />
			<div className={styles.Posts}>
				{filteredPosts.map((post) => (
					<Post post={post} key={post.id} />
				))}
			</div>
			<Nav prevLink={prevLink} nextLink={nextLink} />
			<Footer />
		</>
	);
}

export default Posts;
